INSERT INTO `webinars` (`id`, `title`, `slug`, `description`, `short_description`, `topics`, `cover_image`, `video_url`, `materials_url`, `speaker_video_url`, `broadcast_url`, `scheduled_at`, `duration_minutes`, `timezone`, `speaker_id`, `status`, `is_active`, `is_free`, `certificate_price`, `certificate_hours`, `certificate_template_id`, `meta_title`, `meta_description`, `views_count`, `registrations_count`, `bitrix24_pipeline_id`, `created_at`, `updated_at`) VALUES (5,'«Разговоры о важном» без зевоты: как вовлечь детей в живой диалог на уроке?','razgovory-o-vazhnom-bez-zevoty','<h3>О вебинаре</h3>\n<p>Практическое выступление для классных руководителей о том, как сделать «Разговоры о важном» по-настоящему важными для учеников.</p>\n\n<h3>Вы узнаете:</h3>\n<ul>\n<li>Какие приёмы реально работают — примеры из практики</li>\n<li>Как вовлечь даже самых «сложных» учеников</li>\n<li>Готовые решения, которые можно применить сразу</li>\n<li>Как превратить обязательное занятие в любимое</li>\n</ul>\n\n<h3>Спикер:</h3>\n<p><strong>Чепурин Анатолий Викторович</strong> — Призёр Всероссийского профессионального конкурса «Директор года России 2023», Победитель конкурса «Флагманы образования» 2023, Эксперт созвездия флагманов образования, Директор лицея №2 г. Пермь.</p>\n\n<h3>Для кого:</h3>\n<p>Классные руководители, учителя, педагоги-организаторы, заместители директоров по воспитательной работе.</p>\n\n<h3>Организаторы:</h3>\n<p>Совместный вебинар ФГОС-Практикум и Образовательный центр «Каменный город».</p>','Практические приёмы от Директора года: как сделать Разговоры о важном интересными для учеников','[\"Практические приёмы от Учителя года: как сделать «Разговоры о важном» интересными для учеников\"]',NULL,'https://clck.ru/3RmQ2D',NULL,'/assets/videos/speaker-chepurin.mp4','https://start.bizon365.ru/room/32592/zevaut','2026-02-12 14:00:00',120,'Europe/Moscow',4,'videolecture',1,1,169.00,2,NULL,'«Разговоры о важном» без зевоты: как вовлечь детей в живой диалог на уроке?','Бесплатный вебинар для классных руководителей. Узнайте, как вовлечь учеников в «Разговоры о важном». Спикер — лауреат конкурса «Учитель года России» 2023.',2837,732,'102','2026-01-30 10:02:48','2026-03-04 16:21:41'),(6,'Взаимодействие с семьями воспитанников через читательские марафоны и книжные практики','vzaimodeystvie-s-semyami-vospitannikov-cherez-chitatelskie-marafony','<h3>Актуальность темы</h3>\n<p>Вы замечали, как сложно бывает вовлечь современных родителей в ежедневное чтение с детьми? Нехватка времени, усталость, конкуренция с гаджетами… В итоге ребёнок лишается не только увлекательных историй, но и фундамента для развития речи, воображения и эмоционального интеллекта.</p>\n<p>Мы нашли эффективный инструмент, который поможет вам по-настоящему увлечь детей чтением и сделать родителей своими союзниками.</p>\n\n<h3>Что получат участники</h3>\n<p>Научатся использовать и внедрять в свою практику читательские марафоны для детей и их родителей. Получат готовые инструменты, которые помогут в реализации Программы Просвещения родителей воспитанников.</p>\n\n<h3>Материалы для участников</h3>\n<p>Подборка произведений для запуска марафонов в своей группе, презентация, готовый шаблон объявления для родителей.</p><div style=\"display: flex; gap: 20px; margin-top: 24px; flex-wrap: wrap;\"><img src=\"/assets/images/speakers/speaker-tulaykina-1.jpg\" alt=\"Тулайкина Светлана Олеговна\" style=\"border-radius: 16px; width: 48%; max-width: 350px; height: auto;\"><img src=\"/assets/images/speakers/speaker-tulaykina-2.jpg\" alt=\"Тулайкина Светлана Олеговна\" style=\"border-radius: 16px; width: 48%; max-width: 350px; height: auto;\"></div>\n\n<h3>Полезные материалы</h3>\n<p>Скачайте <a href=\"https://clck.ru/3S4HKT\" target=\"_blank\">презентацию с полезными материалами</a> для использования в работе.</p>','Расскажу про эффективные инструменты мотивации родителей к чтению книг детям, покажу книжные практики, которые помогают вовлечь родителей в образовательный процесс. Разберем как запустить в группе читательские марафоны от начала до завершения.',NULL,'/assets/images/speakers/speaker-tulaykina-1.jpg','https://clck.ru/3S4HUn','https://clck.ru/3S4HKT',NULL,'https://start.bizon365.ru/room/32592/read_marafon','2026-02-25 14:00:00',90,'Europe/Moscow',5,'videolecture',1,1,200.00,2,NULL,'Вебинар: Читательские марафоны и книжные практики для взаимодействия с семьями | Каменный город','Бесплатный вебинар для педагогов: эффективные инструменты мотивации родителей к чтению книг детям, читательские марафоны от начала до завершения.',2739,821,NULL,'2026-02-12 07:26:26','2026-03-05 02:52:50'),(7,'Нейросети в образовании: 5 способов эффективного применения в работе педагога','nejroseti-v-obrazovanii','<h3>О чём вебинар</h3> <p>Искусственный интеллект стремительно меняет образовательную среду. На этом вебинаре вы узнаете, как педагогу использовать нейросети и голосовых помощников не для замены живого общения, а для усиления своей профессиональной деятельности.</p> <h3>Программа вебинара</h3> <ul> <li><strong>Генерация учебных материалов</strong> — как с помощью нейросетей быстро создавать планы уроков, рабочие листы, дидактические карточки и адаптированные тексты</li> <li><strong>Персонализация обучения</strong> — использование ИИ для создания индивидуальных заданий с учётом уровня подготовки каждого ученика</li> <li><strong>Автоматизация рутины</strong> — проверка работ, составление отчётов, анализ успеваемости и формирование обратной связи</li> <li><strong>Интерактивные занятия</strong> — применение голосовых помощников и чат-ботов для вовлечения учеников в учебный процесс</li> <li><strong>Развитие цифровой грамотности</strong> — как научить школьников критически оценивать информацию, созданную нейросетями, и использовать ИИ ответственно</li> </ul> <h3>Для кого этот вебинар</h3> <p>Вебинар будет полезен учителям, воспитателям, методистам и педагогам дополнительного образования, которые хотят идти в ногу со временем и применять современные цифровые инструменты в своей работе.</p> <h3>Что вы получите</h3> <ul> <li>Практические приёмы использования нейросетей, которые можно применить уже на следующем уроке</li> <li>Обзор актуальных ИИ-инструментов для педагога</li> <li>Понимание этических аспектов применения ИИ в образовании</li> <li>Возможность оформить сертификат участника на 2 часа</li> </ul>','На вебинаре рассмотрим потенциал использования нейросетей и голосовых помощников в образовательном процессе.',NULL,NULL,'https://drive.google.com/file/d/1zyf0T74kcTnqxxRiIb5m77O0SvOHFXfu/view?usp=drive_link',NULL,NULL,NULL,'2026-02-18 00:00:00',60,'Europe/Moscow',6,'videolecture',1,1,169.00,2,NULL,'Нейросети в образовании: 5 способов применения для педагога | Каменный город','Бесплатный автовебинар о применении нейросетей и ИИ в работе педагога. Смотрите запись, пройдите тест и получите сертификат на 2 часа.',518,104,NULL,'2026-02-18 05:25:36','2026-03-04 20:20:11'),(8,'Буллинг в детском коллективе: кто и как поможет в решении проблем?','bulling-v-detskom-kollektive','<h3>О чём вебинар</h3> <p>Буллинг — одна из самых острых проблем современной школы. По статистике, каждый третий ребёнок сталкивался с травлей в том или ином виде. На этом вебинаре разберём, как распознать буллинг на ранней стадии, какие алгоритмы работы существуют и кто из специалистов может помочь ребёнку.</p> <h3>Программа вебинара</h3> <ul> <li><strong>Что такое буллинг и чем он отличается от конфликта</strong> — признаки систематической травли, виды буллинга (физический, вербальный, социальный, кибербуллинг)</li> <li><strong>Как распознать буллинг в классе</strong> — маркеры поведения жертвы, агрессора и наблюдателей, на что обратить внимание педагогу и родителю</li> <li><strong>Алгоритм действий педагога</strong> — пошаговый план работы при выявлении случая травли в детском коллективе</li> <li><strong>Кто поможет ребёнку</strong> — роли классного руководителя, психолога, социального педагога, администрации и родителей в решении проблемы</li> <li><strong>Профилактика буллинга</strong> — создание безопасной среды в классе, формирование навыков эмпатии и уважительного общения</li> </ul> <h3>Для кого этот вебинар</h3> <p>Вебинар будет полезен классным руководителям, учителям, воспитателям, школьным психологам, социальным педагогам и родителям, которые хотят понимать механизмы травли и уметь эффективно реагировать на ситуации буллинга.</p> <h3>Что вы получите</h3> <ul> <li>Чёткий алгоритм действий при обнаружении буллинга в детском коллективе</li> <li>Понимание ролей всех участников ситуации и способов взаимодействия с ними</li> <li>Практические инструменты профилактики травли в классе</li> <li>Возможность оформить сертификат участника на 2 часа</li> </ul>','Подберем алгоритм работы с детским коллективом по профилактике буллинга и определим, кто может помочь ребенку справиться с травлей.',NULL,NULL,'https://drive.google.com/file/d/1w92onC6vomNKi1XYNvHLBbWjAytcxQIo/view?usp=sharing',NULL,NULL,NULL,'2026-02-18 00:00:00',60,'Europe/Moscow',7,'videolecture',1,1,169.00,2,NULL,'Буллинг в детском коллективе: кто и как поможет | Каменный город','Бесплатный автовебинар о профилактике буллинга в школе. Алгоритм действий педагога при травле. Смотрите запись, пройдите тест и получите сертификат на 2 часа.',237,34,NULL,'2026-02-18 05:25:36','2026-03-04 16:32:04'),(10,'Как сохранить ресурс и не потерять качество работы при росте требований?','kak-sokhranit-resurs','<h3>О чём вебинар</h3>\n<p>Вебинар предназначен для педагогов, сталкивающихся с увеличением административных и профессиональных требований. В ходе мероприятия участники узнают, как эффективно управлять личными и коллективными ресурсами, чтобы избежать выгорания и сохранить высокий уровень качества образовательного процесса. Особое внимание уделяется практическим методам планирования, делегирования, мотивации и использованию современных инструментов для оптимизации работы.</p>\n\n<h3>Программа вебинара</h3>\n<ul>\n    <li><strong>Управление личной энергией и временем</strong> — эффективные методы планирования рабочего времени, приоритетизации задач и предотвращения профессионального выгорания</li>\n    <li><strong>Развитие стрессоустойчивости</strong> — техники снижения стресса и эмоциональной регуляции для сохранения спокойствия и концентрации в условиях высокой нагрузки</li>\n    <li><strong>Оптимизация рабочих процессов</strong> — способы распределения задач и использования ресурсов для повышения продуктивности без потерь в качестве работы</li>\n    <li><strong>Поддержание высокого качества работы</strong> — как сохранять стандарт и качество образовательного процесса, несмотря на рост внешних и внутренних требований</li>\n    <li><strong>Навыки саморефлексии и самооценки</strong> — развитие способности анализировать собственные ресурсы и вовремя корректировать рабочие подходы</li>\n    <li><strong>Коммуникация и командная работа</strong> — рекомендации по эффективному взаимодействию с коллегами и руководством для совместного улучшения рабочих условий</li>\n</ul>\n\n<h3>В чём актуальность темы</h3>\n<p>В современном образовательном пространстве педагоги сталкиваются с постоянным увеличением объёмов административной и образовательной нагрузки, усложнением нормативных требований и ожиданий со стороны государства, администрации и родителей. Эти факторы приводят к риску профессионального выгорания, снижению эффективности работы и ухудшению качества образовательных услуг.</p>\n<p>Вебинар помогает осознать и преодолеть эти вызовы, предлагая проверенные методы управления личными и коллективными ресурсами. Он способствует сохранению баланса между возросшими требованиями и вашими возможностями, что особенно важно в условиях ограниченного времени и ресурсов.</p>\n\n<h3>Для кого этот вебинар</h3>\n<p>Вебинар будет полезен учителям, воспитателям, методистам, педагогам дополнительного образования, школьным психологам и руководителям образовательных организаций, которые хотят сохранить профессиональный ресурс и повысить качество своей работы.</p>\n\n<h3>Что вы получите</h3>\n<ul>\n    <li>Практические методы управления временем и энергией для профилактики выгорания</li>\n    <li>Техники стрессоустойчивости и эмоциональной регуляции</li>\n    <li>Инструменты оптимизации рабочих процессов и делегирования задач</li>\n    <li>Навыки саморефлексии для своевременной коррекции рабочих подходов</li>\n    <li>Полезные материалы: тест на определение уровня профессионального выгорания, листы-челленджа для улучшения самочувствия</li>\n    <li>Возможность оформить сертификат участника на 2 часа</li>\n</ul>','Вебинар для педагогов о том, как эффективно управлять ресурсами, избежать выгорания и сохранить высокий уровень качества работы при росте требований.',NULL,NULL,NULL,NULL,NULL,'https://start.bizon365.ru/room/32592/resurs_rabota','2026-03-05 14:00:00',120,'Europe/Moscow',9,'scheduled',1,1,200.00,2,NULL,'Как сохранить ресурс и не потерять качество работы | Каменный город','Бесплатный вебинар для педагогов. Практические методы управления ресурсами, профилактика выгорания, оптимизация работы. 5 марта 2026 в 14:00 МСК. Сертификат на 2 часа.',1521,576,NULL,'2026-02-25 05:24:35','2026-03-05 03:24:13'),(12,'Наставник 2026: новые подходы к сопровождению молодых педагогов','nastavnik-2026','<h3>О чём вебинар</h3>\n<p>Старая система наставничества убивает в молодых учителях желание работать, а в опытных — желание учить. Мы теряем людей. На этом вебинаре поговорим о том, как превратить наставничество из скучной обязанности в инструмент спасения кадров и личного роста для обеих сторон. Говорим только по делу — уходим с готовыми инструментами, а не с конспектами.</p>\n\n<h3>Программа вебинара</h3>\n<ul>\n    <li><strong>Экспресс-диагностика молодого педагога</strong> — как за 5 минут понять психотип молодого специалиста и выбрать верный подход с первой встречи</li>\n    <li><strong>Реверсивное наставничество</strong> — как новичок может научить вас: перевернутая модель, которая мотивирует обе стороны</li>\n    <li><strong>Автоматизация контроля</strong> — чек-листы и Trello для наставника: экономим время и видим прогресс без бюрократии</li>\n    <li><strong>Обратная связь без потерь</strong> — разбор кейса: как указать на ошибку и не потерять сотрудника (техника «Сэндвич»)</li>\n    <li><strong>Коучинг вместо приказов</strong> — как задавать вопросы, чтобы новичок сам находил решения</li>\n    <li><strong>Анализ уроков нового формата</strong> — как анализировать уроки по 10-минутным видео, а не сидеть часами в классе</li>\n</ul>\n\n<h3>В чём актуальность темы</h3>\n<p>Тема нашего вебинара актуальна как никогда — не из-за новых приказов Министерства, а потому что мы стоим перед фактом: старая система наставничества убивает в молодых учителях желание работать, а в опытных — желание учить. Мы теряем людей.</p>\n<p>Сегодня поговорим о том, как превратить наставничество из скучной обязанности в инструмент спасения кадров и личного роста для обеих сторон.</p>\n\n<h3>Для кого этот вебинар</h3>\n<p>Вебинар предназначен для заместителей директоров, методистов, руководителей ШМО и опытных педагогов, которые хотят выстроить эффективную систему поддержки молодых специалистов, избежать их быстрого выгорания и превратить наставничество из скучной обязанности в инструмент профессионального роста для обеих сторон.</p>\n\n<h3>Что вы получите</h3>\n<ul>\n    <li><strong>Узнаете:</strong> психологию поколения Z — почему они «выносят мозг» и как найти с ними общий язык</li>\n    <li><strong>Узнаете:</strong> 3 типа молодых специалистов — как не ошибиться с подходом с первой встречи</li>\n    <li><strong>Научитесь:</strong> давать обратную связь без обид и слёз (техника «Сэндвич»)</li>\n    <li><strong>Научитесь:</strong> экономить время — анализировать уроки по 10-минутным видео, а не сидеть часами в классе</li>\n    <li><strong>Научитесь:</strong> использовать коучинг вместо приказов — чтобы новичок сам находил решения</li>\n    <li>Возможность оформить сертификат участника на 2 часа</li>\n</ul>\n\n<h3>Полезные материалы</h3>\n<ul>\n    <li>Чек-лист «Первая встреча с наставником»</li>\n    <li>Шаблон «Карта развития на четверть» (всего 3 навыка для отработки)</li>\n    <li>Алгоритм анализа урока нового формата (не для галочки, а для пользы)</li>\n</ul>','Бесплатный вебинар для заместителей директоров, методистов и опытных педагогов. Как выстроить эффективную систему наставничества, избежать выгорания молодых специалистов и получить готовые инструменты для работы.',NULL,NULL,NULL,NULL,NULL,NULL,'2026-03-19 14:00:00',120,'Europe/Moscow',11,'scheduled',1,1,200.00,2,NULL,'Наставник 2026: новые подходы к сопровождению молодых педагогов | Каменный город','Бесплатный вебинар для заместителей директоров, методистов и педагогов. Новые подходы к наставничеству, готовые инструменты и чек-листы. 19 марта 2026 в 14:00 МСК. Сертификат на 2 часа.',47,3,NULL,'2026-03-04 07:19:46','2026-03-05 00:55:43');
