INSERT INTO `speakers` (`id`, `full_name`, `slug`, `position`, `organization`, `bio`, `photo`, `email`, `is_active`, `display_order`, `created_at`, `updated_at`) VALUES (1,'Иванова Мария Сергеевна','ivanova-maria','Кандидат педагогических наук','ФГБОУ ВО \"Московский педагогический университет\"','Автор более 50 научных публикаций по методике преподавания. Эксперт в области инновационных образовательных технологий.',NULL,NULL,1,1,'2026-01-30 10:00:20','2026-01-30 10:08:34'),(2,'Петров Алексей Николаевич','petrov-alexey','Доцент кафедры педагогики','Институт развития образования','Практикующий педагог с 20-летним стажем. Разработчик авторских методик обучения.',NULL,NULL,1,2,'2026-01-30 10:00:20','2026-01-30 10:08:34'),(3,'Сидорова Елена Владимировна','sidorova-elena','Методист высшей категории','Центр развития образования','Специалист по дошкольному образованию. Автор методических пособий для воспитателей ДОУ.',NULL,NULL,1,3,'2026-01-30 10:00:20','2026-01-30 10:08:34'),(4,'Чепурин Анатолий Викторович','ekspert-fgos-praktikum','Директор лицея №2 г. Пермь','Призёр конкурса «Директор года России» 2023, Победитель конкурса «Флагманы образования» 2023, Эксперт созвездия флагманов образования','Призёр Всероссийского профессионального конкурса «Директор года России 2023», Победитель конкурса «Флагманы образования» 2023, Эксперт созвездия флагманов образования, Директор лицея №2 г. Пермь.','/assets/images/speakers/speaker-chepurin.jpg',NULL,1,10,'2026-01-30 10:02:48','2026-02-06 16:30:18'),(5,'Тулайкина Светлана Олеговна','tulaykina-svetlana','Почетный работник просвещения и воспитания РФ, Лауреат премии мэра Москвы в области образования','Победитель конкурса Воспитатель года Москвы','Победитель конкурса Воспитатель года Москвы, лауреат конкурса Воспитатель года России. Почетный работник просвещения и воспитания РФ, лауреат премии мэра Москвы в области образования.','/assets/images/speakers/speaker-tulaykina-1.jpg',NULL,1,0,'2026-02-12 07:25:16','2026-02-12 07:25:16'),(6,'Минец Диана Владимировна','minets-diana','Кандидат филологических наук, учитель русского языка и литературы высшей квалификационной категории','СО НКО «Обрсоюз» (Москва)','Кандидат филологических наук, учитель русского языка и литературы высшей квалификационной категории. Ведущий методист социально ориентированной некоммерческой организации «Обрсоюз» (Москва). Призер Всероссийского конкурса «Учитель года России-2020», «Цифровой учитель года России-2020». Победитель «Rybakov Foundation Teacher\'s Lab-2020» в номинации «Лучший интерактивный урок для 10−11 класс». Спикер EdCrunch (2019, 2021), главный редактор образовательного блога «Faust». Член Совета учителей-блогеров при Общественном совете при Министерстве Просвещения РФ. Автор и спикер курсов по цифровым инструментам, EdTech-блогер.','/assets/images/speakers/speaker-minets.jpg',NULL,1,0,'2026-02-18 05:25:36','2026-02-18 05:25:36'),(7,'Макарова Вероника Андреевна','makarova-veronika','Советник директора по воспитанию, учитель первой категории','Московская школа №1415 «Останкино»','Советник директора по воспитанию и взаимодействию с детскими общественными объединениями Московской школы №1415 «Останкино», учитель, классный руководитель, учитель первой категории.','/assets/images/speakers/speaker-makarova.png',NULL,1,0,'2026-02-18 05:25:36','2026-02-18 05:25:36'),(9,'Галиева Светлана Юрьевна','galieva-svetlana','Кандидат педагогических наук, доцент кафедры педагогики и психологии ПГГПУ, федеральный эксперт ДПО, семейный психолог','ПГГПУ','Кандидат педагогических наук, доцент кафедры педагогики и психологии Пермского государственного гуманитарно-педагогического университета (ПГГПУ). Федеральный эксперт дополнительного профессионального образования. Семейный психолог. Специалист в области управления личными и коллективными ресурсами педагогов, профилактики профессионального выгорания и повышения эффективности образовательного процесса.','/assets/images/speakers/speaker-galieva.jpg',NULL,1,0,'2026-02-25 05:24:35','2026-02-25 05:24:35'),(11,'Кощеева Анастасия Николаевна','koscheeva-anastasiya','Заслуженный учитель РФ, Почётный работник общего образования РФ, эксперт ЕГЭ','Региональный представитель ВСНП в Пермском крае','Заслуженный учитель РФ, Почётный работник общего образования РФ. Победитель конкурса на присуждение премий лучшим учителям России за достижения в педагогической деятельности (2008, 2023). Победитель Всероссийского конкурса учителей физики, математики, химии и биологии в номинации «Наставник будущих учёных» (2015). Региональный представитель ВСНП в Пермском крае, эксперт ЕГЭ. Награждена Почётной грамотой Министерства образования и науки РФ, Благодарственным письмом министра просвещения РФ, Благодарственным письмом губернатора Пермского края. Неоднократно отмечена Почётными грамотами Главного отдела народного образования Исполкома Пермского областного Совета народных депутатов. Успешно прошла конкурсные отборы на участие в программах повышения квалификации в Образовательном центре «Сириус» (2021, 2022). Участник Всероссийских съездов учителей и преподавателей химии (2012, 2022, 2023), Всероссийских конференций «Кадровый резерв российской химии» (2012, 2014, 2017), Всероссийских Форумов классных руководителей (2021, 2022, 2023). Участник телешоу «Классная тема» (2022). Лауреат городского этапа конкурса «Учитель года — 2011», победитель интернет-голосования краевого конкурса «Учитель года — 2011». Занесена в Книгу Почёта отрасли образования города Перми.','/assets/images/speakers/speaker-koscheeva.jpg',NULL,1,0,'2026-03-04 07:19:46','2026-03-04 07:19:46');
